#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Parallelise over the outermost dimension.
       Each thread works on a chunk of rows of B, thus avoiding
       false sharing. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Local pointers to the start of the i‑th row of B
        double* Bi = B[i].data();
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // Loop over k > i – the upper‑triangular part of A^T
            // (i.e. lower‑triangular part of A)
#pragma simd  // vectorise inner loop
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            Bi[j] = alpha * (Bi[j] + sum);
        }
    }
}
