constexpr double coeff = 1.0 / 3.0;   // Exactly 0.333333…

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    double* __restrict a = A.data();
    double* __restrict b = B.data();

    for (int t = 0; t < tsteps; ++t) {
        /* First half–step: update B from A */
#pragma omp parallel for schedule(static) shared(a,b,n)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second half–step: update A from B */
#pragma omp parallel for schedule(static) shared(a,b,n)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
