#include <vector>
#include <algorithm>
#include <omp.h>

// Floyd–Warshall with cache‑friendly layout and OpenMP parallelisation.
// The original signature is preserved: `int n` and a 2D vector `path`.
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path)
{
    // Flatten the 2‑D vector to a 1‑D array for better spatial locality.
    // We will work in place, so we just keep a pointer to the first row.
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    // Parallelise over k – outermost loop is the most expensive.
    // Each thread works on a distinct k value, so no race condition.
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int kBase = k * n;
        // We can unroll the inner j loop a bit for speed.
        for (int i = 0; i < n; ++i) {
            int iBase = i * n;
            int aik = flat[iBase + k];
            // If the intermediate distance is INF (large value) we can skip.
            if (aik == INT_MAX) continue;
            for (int j = 0; j < n; ++j) {
                int val = aik + flat[kBase + j];
                if (val < flat[iBase + j]) flat[iBase + j] = val;
            }
        }
    }

    // Write results back to the original 2‑D vector.
    for (int i = 0; i < n; ++i)
        std::move(flat.begin() + i * n, flat.begin() + (i + 1) * n, path[i].begin());
}
