    const std::vector<double*> row_ptrs(n);
    for (int i = 0; i < n; ++i)
        row_ptrs[i] = A[i].data();

    // Parallel over the outer loop; inner loop is small enough
    // to keep the work per thread balanced.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* a_row = row_ptrs[i];
        double xi1 = x1p[i];          // read once
        double xi2 = x2p[i];          // read once

        for (int j = 0; j < n; ++j) {
            xi1 += a_row[j] * y1[j];  // A[i][j] * y1[j]
