/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {
    // Flatten the 2‑D input matrices into 1‑D views for better cache locality.
    const std::size_t stride = static_cast<std::size_t>(n);
    const double* A_flat = reinterpret_cast<const double*>(A[0].data());
    const double* B_flat = reinterpret_cast<const double*>(B[0].data());
    const double* x_arr   = x.data();
    double*       tmp_arr = tmp.data();
    double*       y_arr   = y.data();

    // Optimal block size: tune experimentally or use a compile‑time constant.
    const std::size_t block = 32; // cache‑friendly tile size

    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < n; ii += block) {
        const std::size_t i_end = (ii + block < n) ? (ii + block) : n;
        for (int i = ii; i < i_end; ++i) {
            double tmp_val = 0.0;
            double y_val   = 0.0;
            const std::size_t base_i = static_cast<std::size_t>(i) * stride;
            for (int j = 0; j < n; ++j) {
                const double xj = x_arr[j];
                tmp_val += A_flat[base_i + j] * xj;
                y_val   += B_flat[base_i + j] * xj;
            }
            tmp_arr[i] = tmp_val;
            y_arr[i]  = alpha * tmp_val + beta * y_val;
        }
    }
}
