/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<double>>& C4,
		    std::vector<double>& sum) {
    // Parallelise the outer two loops. The inner work per element is tiny,
    // so collapsing the loops gives enough parallel work.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // Pointers to the row of A and the matrix C4
            double* const a_row     = &A[r][q][0];
            double* const c4_row_s  = &C4[0][0];   // C4 is stored as C4[s][p]
            const int  stride_c4 = np;             // stride of C4 in memory

            for (int p = 0; p < np; ++p)
                sum[p] = 0.0;

            // Compute temporary sum for this (r,q) pair
            for (int s = 0; s < np; ++s) {
                double a_val = a_row[s];
                const double* c4_ptr = c4_row_s + s * stride_c4;
                for (int p = 0; p < np; ++p)
                    sum[p] += a_val * c4_ptr[p];
            }

            // Write the result back to A
            double* a_res = &A[r][q][0];
            for (int p = 0; p < np; ++p)
                a_res[p] = sum[p];
        }
    }
}
