/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // The input is a square matrix A with dimension n x n
    // We assume all rows are contiguous and of equal length.
    // We use a flat pointer to enable efficient indexing and
    // take advantage of OpenMP parallelism.
    double* data = A[0].data();   // pointer to the first element

    const std::size_t stride = static_cast<std::size_t>(n);

    for (int t = 0; t < tsteps; ++t) {
        // Parallelize the i-j loops; collapse(2) allows nested loops
        // to be flattened, giving more parallel work and better load
        // balance for larger n.
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            const std::size_t i_n = static_cast<std::size_t>(i) * stride;

            for (int j = 1; j <= n - 2; ++j) {
                const std::size_t idx  = i_n + j;
                const std::size_t idxm1 = i_n + j - 1;
                const std::size_t idxp1 = i_n + j + 1;

                const std::size_t iup   = (i - 1) * stride;
                const std::size_t idown = (i + 1) * stride;

                double sum =
                    data[iup   + j - 1] + data[iup   + j] + data[iup   + j + 1] +
                    data[idxm1]            + data[idx]            + data[idxp1]            +
                    data[idown + j - 1] + data[idown + j] + data[idown + j + 1];
                data[idx] = sum / 9.0;
            }
        }
    }
}
