/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // Initialise y to zero (serial or parallel does not matter for correctness)
    std::fill(y.begin(), y.end(), 0.0);

#pragma omp parallel
    {
        // Each thread keeps its own contribution to y
        std::vector<double> y_local(n, 0.0);

#pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double sum = 0.0;
            const double* row = A[i].data();   // pointer to the i‑th row
            // Compute tmp[i] = A[i] · x
            for (int j = 0; j < n; ++j) {
                sum += row[j] * x[j];
            }
            tmp[i] = sum;

            // Accumulate contribution to y
            for (int j = 0; j < n; ++j) {
                y_local[j] += row[j] * sum;
            }
        }

        // Merge thread‑local y contributions into the global y
#pragma omp critical
        {
            for (int j = 0; j < n; ++j) {
                y[j] += y_local[j];
            }
        }
    }
}
