#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    constexpr double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* 1. Compute means ----------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    /* 2. Compute stddevs --------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            const double diff = data[i][j] - mu;
            sum_sq += diff * diff;
        }
        double s = std::sqrt(sum_sq / static_cast<double>(n));
        stddev[j] = (s <= eps) ? 1.0 : s;
    }

    /* 3. Standardize data --------------------------------------------------- */
    const double inv_sqrt_n_const = inv_sqrt_n;          // avoid recompute
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] -= mean[j];
            data[i][j] *= inv_sqrt_n_const / stddev[j];
        }
    }

    /* 4. Compute correlation matrix ---------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) s += data[k][i] * data[k][j];
            corr[i][j] = corr[j][i] = s;
        }
    }
}
