/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    // Helper: 1 if bases match (A+U=U+A or C+G=G+C), 0 otherwise.
    auto match = [](int b1, int b2) -> int {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    // Flatten the 2D table to a 1D array for better cache behaviour.
    // table[i][j] is stored at flat[i * n + j]
    std::vector<int> flat(n * n, 0);

    // Pre‑copy the outer vector to avoid bounds checks inside the hot loop.
    const int *seq_ptr = seq.data();

    // Dynamic programming: fill the table by increasing distance (len).
    // This allows easy parallelisation over the i‑loop for each len.
    #pragma omp parallel for schedule(static)
    for (int len = 2; len <= n; ++len) {  // len = j-i+1
        int max_i = n - len;
        for (int i = 0; i <= max_i; ++i) {
            int j = i + len - 1;
            int idx = i * n + j;

            int best = 0;

            // skip j
            best = std::max(best, flat[i * n + (j - 1)]);

            // skip i
            best = std::max(best, flat[(i + 1) * n + j]);

            // pair (i,j)
            if (i < j - 1) {
                best = std::max(best, flat[(i + 1) * n + (j - 1)] + match(seq_ptr[i], seq_ptr[j]));
            } else {
                best = std::max(best, flat[(i + 1) * n + (j - 1)]);
            }

            // split at k
            int* row_i = &flat[i * n];
            int* row_k = nullptr;
            for (int k = i + 1; k < j; ++k) {
                int tmp = row_i[k] + *(&flat[(k + 1) * n + j]);
                if (tmp > best) best = tmp;
            }

            flat[idx] = best;
        }
    }

    // Write results back to the original 2D structure.
    for (int i = 0; i < n; ++i) {
        std::memcpy(table[i].data(), &flat[i * n], n * sizeof(int));
    }
}
