/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {
    // 1st loop – update A
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        auto Ai = A[i].data();          // pointer to row i
        double ui1 = u1[i];
        double ui2 = u2[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // 2nd loop – update x (independent per i)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    // 3rd loop – add z to x
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    // 4th loop – accumulate into w
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        auto Ai = A[i].data();          // pointer to row i
        for (int j = 0; j < n; ++j) {
            wi += alpha * Ai[j] * x[j];
        }
        w[i] = wi;
