/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    // Ensure the matrix is square and of the expected size
    assert(static_cast<int>(A.size()) == n);
    for (auto& row : A)
        assert(static_cast<int>(row.size()) == n);

    /* Each row i of the Cholesky factor only depends on rows
       0..i‑1.  Therefore the outer i‑loop can be safely parallelised.
       The inner j‑loop is intrinsically sequential because
       A[i][j] depends on A[i][k] for k < j.  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Process the sub‑diagonal entries of row i
        for (int j = 0; j < i; ++j) {
            double sum = A[i][j];
            for (int k = 0; k < j; ++k) {
                sum -= A[i][k] * A[j][k];
            }
            A[i][j] = sum / A[j][j];
        }

        // Compute the diagonal entry A[i][i]
        double sum = A[i][i];
        for (int k = 0; k < i; ++k) {
            sum -= A[i][k] * A[i][k];
        }
        A[i][i] = std::sqrt(sum);
