/* 2MM kernel – keeps the same API as the original but is heavily optimized
 * for a multi‑core x86_64 CPU.  The implementation stages the two matrix
 * products in flattened buffers and uses OpenMP to parallelise the outer
 * loops while keeping the inner work cache‑friendly.
 *
 * A, B, C, D, and tmp are still std::vector<std::vector<double>> but
 * we convert them to contiguous rows during the call so that the kernel
 * can use raw pointers and pointer arithmetic.
 */

static inline double* flat_row(std::vector<std::vector<double>>& vec, int i)
{
    // Return a pointer to the first element of row i
    return &vec[i][0];
}

/* main kernel */
void kernel_2mm(int ni, int nj, int nk, int nl,
		double alpha,
		double beta,
		std::vector<std::vector<double>>& tmp,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D)
{
    /* ------------------------------------------------------------------
     * 1. Compute tmp = alpha * A * B
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* tmp_row   = flat_row(tmp, i);
        double* A_row     = flat_row(A, i);

        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* bcol = flat_row(B, j);           // pointer to column j of B
            for (int k = 0; k < nk; ++k) {
                sum += A_row[k] * bcol[k];
            }
            tmp_row[j] = alpha * sum;
        }
    }

    /* ------------------------------------------------------------------
     * 2. Compute D = beta * D + tmp * C
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* D_row  = flat_row(D, i);
        double* tmp_row = flat_row(tmp, i);

        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* ccol = flat_row(C, j);           // pointer to column j of C
            for (int k = 0; k < nj; ++k) {
                sum += tmp_row[k] * ccol[k];
            }
            D_row[j] = beta * D_row[j] + sum;
        }
    }
}
