 * The numerical behaviour is identical to the reference implementation.
 */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Temporary alias for the input vectors
    double *xptr = x.data();
    const double *bptr = b.data();

    // Iterate over the rows of L
    for (int i = 0; i < n; ++i) {
        const double *row = L[i].data();          // pointer to row i
        const int  row_len = i;                   // number of lower triangular elements
        double sum = 0.0;

        /* Dot‑product of L[i][0..i-1] with x[0..i-1].
         * Manual loop unrolling gives the compiler more optimisation
         * opportunities on x86‑64 (FMA, AVX, etc.) and removes bounds checks.
         * The unroll factor is 4; the remaining elements are handled
         * by a small tail loop. */
        int k = 0;
        const int unroll = 4;
        const int limit = row_len - (row_len % unroll);
        for (; k < limit; k += unroll) {
            sum += row[k]     * xptr[k];
            sum += row[k + 1] * xptr[k + 1];
            sum += row[k + 2] * xptr[k + 2];
            sum += row[k + 3] * xptr[k + 3];
        }
        for (; k < row_len; ++k) {
            sum += row[k] * xptr[k];
        }

        // Compute the i‑th component
        xptr[i] = (bptr[i] - sum) / row[i];
    }
}
