/*  LU factorisation with partial pivoting removed because the original
    kernel does not perform any pivoting.  The array A is flattened
    into a single contiguous vector to improve cache locality.  The
    function signature is kept identical to the one used by the harness.
*/

/* Forward declaration of helper for flattened indexing */
inline constexpr size_t idx(size_t i, size_t j, size_t n) noexcept {
    return i * n + j;
}

void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ---------- Build a contiguous copy of A ---------- */
    std::vector<double> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flat.begin() + i * n);

    /* ---------- LU decomposition (L has unit diagonal) ---------- */
    for (int i = 0; i < n; ++i) {
        /* compute U(i, j) for j = i .. n-1 */
        for (int j = i; j < n; ++j) {
            double sum = flat[idx(i, j, n)];
            for (int k = 0; k < i; ++k)
                sum -= flat[idx(i, k, n)] * flat[idx(k, j, n)];
            flat[idx(i, j, n)] = sum;
        }

        /* compute L(i, j) for j = 0 .. i-1 */
        double denom = flat[idx(i, i, n)];
        for (int j = 0; j < i; ++j) {
            double sum = flat[idx(i, j, n)];
            for (int k = 0; k < j; ++k)
                sum -= flat[idx(i, k, n)] * flat[idx(k, j, n)];
            flat[idx(i, j, n)] = sum / denom;
        }
    }

    /* ---------- Forward substitution: solve Ly = b ---------- */
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        for (int j = 0; j < i; ++j)
            sum -= flat[idx(i, j, n)] * y[j];
        y[i] = sum;   // L(i,i) == 1
    }

    /* ---------- Backward substitution: solve Ux = y ---------- */
    for (int i = n - 1; i >= 0; --i) {
        double sum = y[i];
        for (int j = i + 1; j < n; ++j)
            sum -= flat[idx(i, j, n)] * x[j];
        x[i] = sum / flat[idx(i, i, n)];
    }
}
