    const double* restrict rp = r.data();
          double* restrict yp = y.data();

    // Allocate auxiliary buffer once
    double* restrict z = new double[n];

    // Initialise first coefficients
    yp[0] = -rp[0];
    double beta  = 1.0;
    double alpha = -rp[0];

    for (int k = 1; k < n; ++k)
    {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute dot product sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* restrict rr = rp + k - 1;   // start at r[k-1]
        const double* restrict yy = yp;           // start at y[0]
        for (int i = 0; i < k; ++i)
        {
            sum += *rr * *yy;
            --rr;    // r[k-i-1] decrements
            ++yy;    // y[i] increments
        }

        // New reflection coefficient
        alpha = -(rp[k] + sum) / beta;

        // Update reflection coefficients y[0..k-1] into z
        const double* restrict yy0 = yp;
        const double* restrict yy1 = yp + k - 1;
        for (int i = 0; i < k; ++i)
        {
            z[i] = *yy0 + alpha * *yy1;
            ++yy0;
            --yy1;
        }

        // Copy updated coefficients back to y
        for (int i = 0; i < k; ++i)
            yp[i] = z[i];

        // Store new coefficient
        yp[k] = alpha;
    }

    // Clean up
    delete[] z;
