/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {

    const double fac = alpha;          // alpha will be reused many times
    const int n1 = n;                  // shorten bounds lookup

    // Parallel over the outer dimension: each thread works on a distinct set of rows i
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n1; ++i) {
        // First scale the lower triangular part of C by beta
        std::vector<double>& Ci = C[i];          // row i of C
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        // Update C[i][j] += alpha * (A[j][k]*B[i][k] + B[j][k]*A[i][k])
        // for all k and j <= i
        const std::vector<double>& Bi = B[i];    // row i of B
        for (int k = 0; k < m; ++k) {
            double Bi_k = Bi[k];
            for (int j = 0; j <= i; ++j) {
                const double Ajk = A[j][k];
                const double Bjk = B[j][k];
                const double Ai_k = A[i][k];
                Ci[j] += fac * (Ajk * Bi_k + Bjk * Ai_k);
            }
        }
    }
}
