```cpp
#include <cmath>
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Flatten A and Q into contiguous buffers for cache efficiency
    const int size = m * n;
    std::vector<double> Abuf(size);
    std::vector<double> Qbuf(size);
    std::vector<double> Rbuf(n * n);  // square matrix, square layout

    // Copy input A into buffer
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
        std::copy(A[i].begin(), A[i].end(), Abuf.begin() + i * n);

    // Main algorithm on buffers
    for (int k = 0; k < n; ++k) {
        // Compute norm = sqrt(sum_i A[i][k]^2)
        double norm = 0.0;
        #pragma omp parallel for reduction(+:norm) schedule(static)
        for (int i = 0; i < m; ++i)
            norm += Abuf[i * n + k] * Abuf[i * n + k];
        norm = std::sqrt(norm);

        // Store R[k][k]
        Rbuf[k * n + k] = norm;

        // Compute Q[i][k] = A[i][k] / norm
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Qbuf[i * n + k] = Abuf[i * n + k] / norm;

        // For all remaining columns j > k
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;
            // Compute R[k][j] = sum_i Q[i][k] * A[i][j]
            #pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i)
                rkj += Qbuf[i * n + k] * Abuf[i * n + j];
            Rbuf[k * n + j] = rkj;

            // Update A[i][j] = A[i][j] - Q[i][k] * rkj
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                Abuf[i * n + j] -= Qbuf[i * n + k] * rkj;
        }
    }

    // Copy Rbuf back to R
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        std::copy(Rbuf.begin() + i * n, Rbuf.begin() + (i + 1) * n, R[i].begin());

    // Copy Qbuf back to Q
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
        std::copy(Qbuf.begin() + i * n, Qbuf.begin() + (i + 1) * n, Q[i].begin());
}
