#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Optimized version – preserves exact semantics */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* pre‑compute constants once */
    const float expAlpha  = std::exp(static_cast<float>(alpha));
    const float expNegA   = std::exp(-static_cast<float>(alpha));
    const float expNeg2A  = std::exp(-2.0f * static_cast<float>(alpha));
    const float k = 1.0f - expNegA * (1.0f - expNegA) /
                     (1.0f + 2.0f * static_cast<float>(alpha) * expNegA -
                      expNeg2A);

    /* coefficients */
    const float a1 = k, a5 = k;
    const float a2 = k * expNegA * (static_cast<float>(alpha) - 1.0f),
                a6 = a2;
    const float a3 = k * expNegA * (static_cast<float>(alpha) + 1.0f),
                a7 = a3;
    const float a4 = -k * expNeg2A, a8 = a4;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -expNeg2A;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ------------------------------------------------------- */
    /* 1. forward pass, rows (imageIn -> y1)                    */
    /* ------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const float* in  = imgIn[i].data();
        float*    y1row = y1[i].data();

        float ym1 = 0.0f, ym2 = 0.0f;
        float xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            float x = in[j];
            y1row[j] = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = x;
            ym2 = ym1;
            ym1 = y1row[j];
        }
    }

    /* ------------------------------------------------------- */
    /* 2. backward pass, rows (imageIn -> y2)                  */
    /* ------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const float* in  = imgIn[i].data();
        float*    y2row = y2[i].data();

        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2row[j] = y;
            xp2 = xp1;
            xp1 = in[j];
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* ------------------------------------------------------- */
    /* 3. combine rows into imgOut                               */
    /* ------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* ------------------------------------------------------- */
    /* 4. forward pass, columns (imgOut -> y1)                  */
    /* ------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float x = imgOut[i][j];
            y1[i][j] = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = x;
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* ------------------------------------------------------- */
    /* 5. backward pass, columns (imgOut -> y2)                */
    /* ------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f;
        float yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;
            tp1 = imgOut[i][j];
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* ------------------------------------------------------- */
    /* 6. final combination into imgOut                         */
    /* ------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
